"// content_script.js - injects overlay UI and communicates with background

// Create overlay container
const overlay = document.createElement('div');
overlay.id = 'ai-agent-overlay';
overlay.style.position = 'fixed';
overlay.style.top = '0';
overlay.style.right = '0';
overlay.style.width = '350px';
overlay.style.height = '100vh';
overlay.style.background = 'rgba(30,30,30,0.9)';
overlay.style.backdropFilter = 'blur(8px)';
overlay.style.zIndex = '2147483647';
overlay.style.overflowY = 'auto';
overlay.style.color = '#fff';
overlay.style.padding = '10px';
overlay.style.fontFamily = '"Inter", sans-serif';

document.body.appendChild(overlay);

// Simple UI to list tasks
const taskList = document.createElement('ul');
taskList.id = 'ai-task-list';
overlay.appendChild(taskList);

// Request current tasks from backend
chrome.runtime.sendMessage({type: 'apiRequest', endpoint: 'tasks', method: 'GET'}, response => {
  if (response.success) {
    response.data.tasks.forEach(task => {
      const li = document.createElement('li');
      li.textContent = task.title;
      li.style.cursor = 'pointer';
      li.addEventListener('click', () => {
        // Open revision modal (simplified for demo)
        const newDesc = prompt('Edit task description:', task.description);
        if (newDesc !== null) {
          chrome.runtime.sendMessage({type: 'apiRequest', endpoint: `tasks/${task.id}`, method: 'PUT', body: {description: newDesc}}, resp => {
            if (resp.success) location.reload();
          });
        }
      });
      taskList.appendChild(li);
    });
  } else {
    console.error('Failed to fetch tasks', response.error);
  }
});
